INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '7e040540-ce31-4cb9-8c31-18b031de5605',
  '00000000-0000-0000-0000-000000000001',
  $escape$styled-components — Why CSS-in-JS Won and When to Reach for Something Else$escape$,
  $escape$styled-components collocates styles with components, giving you scoped CSS, dead-code elimination via tree-shaking, and dynamic styles driven by props — all without a single class name collision. That's the real win over plain CSS or CSS Modules: your `Button` carries its styles wherever it goes, and variant logic lives in JS where it belongs.

But the tradeoff is runtime cost. styled-components injects styles into the DOM at render time via a `StyleSheet` singleton. In a heavily interactive app, the `css` helper and interpolated props can create hundreds of unique class hashes per session. Utility-first (Tailwind) avoids this entirely — static classes, zero runtime. CSS Modules sit in between: build-time scoping, no JS overhead, but no prop-driven dynamism.

The pragmatic call: use styled-components when your design system needs component-level theming via `ThemeProvider` and dynamic variants via props. Switch to CSS Modules for static, performance-critical pages (landing, blog). Never mix both in the same component tree — the cognitive overhead kills the benefit of either approach.$escape$,
  $escape$import styled, { css } from 'styled-components';

type ButtonProps = { variant: 'primary' | 'ghost'; size: 'sm' | 'md' };

const Button = styled.button<ButtonProps>`
  padding: ${({ size }) => (size === 'sm' ? '4px 8px' : '8px 16px')};
  border-radius: 6px;

  ${({ variant, theme }) =>
    variant === 'primary'
      ? css`
          background: ${theme.colors.brand};
          color: #fff;
        `
      : css`
          background: transparent;
          border: 1px solid ${theme.colors.brand};
        `}
`;$escape$,
  $escape$typescript$escape$,
