INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'deadeabc-930f-4333-909f-21a0743f7140',
  '00000000-0000-0000-0000-000000000001',
  $escape$styled_components — Replicating CVA-Style Variant Maps Without the Extra Dependency$escape$,
  $escape$cva and tailwind-variants solve a Tailwind problem: mapping prop combinations to class strings. styled_components doesn't need them — it already has the `css` helper, which compiles tagged template literals into `RuleSet` objects at parse time, not render time. That distinction matters: a variant map of `css\`\`` blocks pays the interpolation cost once, not on every render.

The pattern is a plain object keyed by variant name, each value a `css\`\`` block. Typed with `Record<Variant, ReturnType<typeof css>>` (or inferred via `satisfies`), it gives you the same call-site type safety cva provides — without className juggling.

Use transient props (`$size`, `$variant`) so style props never reach the DOM, a hard requirement since styled-components v5.1. The styled component's generic `styled.button<Props>` enforces the contract at usage.

Compound variants are just map lookups composed in the template: `${({ $size, $variant }) => compoundMap[$size][$variant]}`. You can colocate the maps or extract them to a shared theme token file for cross-component reuse — the same file that feeds your `DefaultTheme`. No peer dependencies, no className abstractions leaking into JSX.$escape$,
  $escape$import styled, { css } from 'styled-components';

const sizeMap = {
  sm: css`padding: 4px 8px; font-size: 12px;`,
  md: css`padding: 8px 16px; font-size: 14px;`,
  lg: css`padding: 12px 24px; font-size: 16px;`,
};
const variantMap = {
  primary: css`background: #6366f1; color: #fff;`,
  ghost:   css`border: 1px solid #6366f1; background: transparent;`,
  danger:  css`background: #ef4444; color: #fff;`,
};
type P = { $size?: keyof typeof sizeMap; $variant?: keyof typeof variantMap };

export const Button = styled.button<P>`
  border-radius: 6px;
  ${({ $size = 'md' }) => sizeMap[$size]}
  ${({ $variant = 'primary' }) => variantMap[$variant]}
`;$escape$,
  $escape$typescript$escape$,
