INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '2ff43515-388b-40b4-9435-4665658ba5b0',
  '00000000-0000-0000-0000-000000000001',
  $escape$styled_components Dark Mode — CSS Custom Properties, prefers-color-scheme, and Killing the Flash$escape$,
  $escape$styled_components' ThemeProvider injects theme values via React context, meaning theme-dependent styles resolve after hydration — causing a visible flash on first load. CSS custom properties sidestep this entirely.

Define your color tokens inside `createGlobalStyle` at `:root`, then override them inside a `prefers-color-scheme: dark` media query. Because `createGlobalStyle` emits a `<style>` tag during SSR (or static generation), the browser resolves those variables before the first paint — zero flash. Components reference `var(--token)` directly in template literals instead of pulling from ThemeProvider.

For user-toggled dark mode, add a `data-theme='dark'` attribute on `<html>` and mirror the overrides under `[data-theme='dark']`. A tiny inline `<script>` in `<head>` — executed synchronously before any React bundle — reads `localStorage` and sets the attribute, preserving the user's preference without hydration delay.

You can keep ThemeProvider for non-color tokens (spacing, radius, typography scale) where flash is invisible. But color primitives belong in CSS variables — that's the only way styled_components can be flash-free without a blocking script per token.$escape$,
  $escape$import { createGlobalStyle, styled } from 'styled-components';

const GlobalTheme = createGlobalStyle`
  :root { --bg: #fff; --fg: #111; --accent: #0070f3; }

  @media (prefers-color-scheme: dark) {
    :root { --bg: #111; --fg: #f0f0f0; --accent: #60a5fa; }
  }

  [data-theme='dark'] { --bg: #111; --fg: #f0f0f0; --accent: #60a5fa; }
`;

const Surface = styled.div`
  background: var(--bg);
  color: var(--fg);
`;$escape$,
  $escape$typescript$escape$,
