INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '4749ed3c-828e-4a2c-9d60-4da5e9ae4d81',
  '00000000-0000-0000-0000-000000000001',
  $escape$styled_components — Type Scale, Font Loading, and font-display Swap Done Right$escape$,
  $escape$Define your type scale once using styled-components' `css` helper and `ThemeProvider`. Expose a `fontSizes` map on the theme so every component pulls from a single source of truth — no magic pixel values scattered across files.

For font loading, pair `createGlobalStyle` with `@font-face` declarations directly in your styled-components setup. This keeps font strategy co-located with your design tokens instead of buried in a separate CSS file. Set `font-display: swap` inside that `@font-face` block so the browser renders fallback text immediately and swaps in the web font once it loads — critical for CLS.

Preload the woff2 variant in your `<head>` via a `<link rel='preload'>` tag; `createGlobalStyle` handles the `@font-face` registration but cannot trigger network preloads, so the HTML-level hint is still necessary. Use `font-weight` descriptors in `@font-face` to define variable font ranges when applicable, letting the browser pick the right axis instead of synthesizing bold or italic — which defeats the performance gain entirely.$escape$,
  $escape$import { createGlobalStyle, ThemeProvider, css } from 'styled-components';

const theme = {
  fontSizes: { xs: '0.75rem', sm: '0.875rem', base: '1rem', lg: '1.25rem', xl: '1.5rem', '2xl': '2rem' },
  fonts: { sans: "'Inter', system-ui, sans-serif" },
};

const GlobalStyle = createGlobalStyle`
  @font-face {
    font-family: 'Inter';
    src: url('/fonts/inter-var.woff2') format('woff2');
    font-weight: 100 900;
    font-display: swap;
  }

  body {
    font-family: ${({ theme }) => theme.fonts.sans};
    font-size: ${({ theme }) => theme.fontSizes.base};
  }
`;

const Heading = styled.h1`
  font-size: ${({ theme }) => theme.fontSizes['2xl']};
  font-weight: 700;
  line-height: 1.2;
`;

export function App() {
  return (
    <ThemeProvider theme={theme}>
      <GlobalStyle />
      <Heading>Hello, type scale</Heading>
    </ThemeProvider>
  );
}$escape$,
  $escape$typescript$escape$,
