INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '0fa5f65e-6d0f-47df-a49b-56b8dc44e0d1',
  '00000000-0000-0000-0000-000000000001',
  $escape$styled_components Color System — Semantic Tokens, Palette Design, and WCAG Contrast$escape$,
  $escape$Raw hex values scattered across styled_components files are a maintenance trap. Instead, build a two-layer token system: a primitive palette and a semantic layer on top. The primitive layer is pure values — `gray100` through `gray900`, `blue500`, etc. The semantic layer maps intent to primitives — `textPrimary`, `surfaceError`, `borderFocus`. Inject both into styled_components via `ThemeProvider`. Consuming components reference semantic tokens only, never primitives directly. This makes dark mode a theme swap, not a component rewrite. For accessibility, WCAG 2.1 AA requires a contrast ratio of 4.5:1 for normal text and 3:1 for large text (18px+ or 14px+ bold). Validate at design time using a tool like `polished`'s `readableColor` or `meetsContrastGuidelines` — import them directly into your theme file so the constraint is enforced at the token definition level, not left to per-component audits. Keep your semantic tokens environment-aware by exporting a `lightTheme` and `darkTheme` object and switching via a single `ThemeProvider` prop.$escape$,
  $escape$import { meetsContrastGuidelines } from 'polished';
import { ThemeProvider } from 'styled-components';

const palette = {
  gray900: '#111827',
  gray50:  '#F9FAFB',
  blue600: '#2563EB',
  white:   '#FFFFFF',
};

const validate = (bg: string, fg: string) => {
  const result = meetsContrastGuidelines(fg, bg);
  if (!result.AA) throw new Error(`Contrast fail: ${fg} on ${bg}`);
};

validate(palette.gray900, palette.white); // textPrimary on surface
validate(palette.blue600, palette.white); // brand on surface

export const lightTheme = {
  textPrimary:   palette.gray900,
  textInverse:   palette.white,
  surfaceBrand:  palette.blue600,
  surface:       palette.gray50,
};

// In app root:
// <ThemeProvider theme={lightTheme}>...</ThemeProvider>$escape$,
  $escape$typescript$escape$,
