INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '562c525f-fd46-472c-94c5-a55559372a48',
  '00000000-0000-0000-0000-000000000001',
  $escape$styled-components Animations — GPU-Composited Properties and prefers-reduced-motion$escape$,
  $escape$styled-components' `keyframes` helper generates hashed, scoped animation names — no global @keyframes collisions. The performance constraint is hardware: only `transform` and `opacity` run on the compositor thread. Animating `top`, `left`, `width`, or `background-color` forces layout and paint recalculation on the main thread, spiking frame times. Stick to transform/opacity exclusively.

For accessibility, inline `@media (prefers-reduced-motion: reduce)` directly inside your `styled` block — don't reach for `createGlobalStyle`. Co-locating the override with the component keeps the motion contract explicit and reviewable. Use `animation: none` for users who opt out, never `animation-duration: 0.001ms` (a WCAG anti-pattern that still fires JS animation events).

For prop-driven conditional animations, compose with the `css` helper alongside `keyframes`. This preserves TypeScript inference on transient props (`$animate`) and prevents raw string interpolation from stripping types. The `both` fill-mode ensures the element holds its final state after the animation completes without needing extra CSS resets.$escape$,
  $escape$import styled, { keyframes, css } from 'styled-components';

const fadeUp = keyframes`
  from { opacity: 0; transform: translateY(8px); }
  to   { opacity: 1; transform: translateY(0); }
`;

const motionMixin = css`
  animation: ${fadeUp} 220ms ease-out both;

  @media (prefers-reduced-motion: reduce) {
    animation: none;
    opacity: 1;
  }
`;

export const Card = styled.div<{ $animate?: boolean }>`
  ${({ $animate }) => $animate && motionMixin}
`;$escape$,
  $escape$typescript$escape$,
