INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '0eeb8fd6-ef00-4ca2-a251-1e711205bf57',
  '00000000-0000-0000-0000-000000000001',
  $escape$styled_components — Global Styles Without the Leakage$escape$,
  $escape$styled_components scopes all styles by default via hashed classnames, but you still need a global baseline — resets, font stacks, box-sizing. That's where `createGlobalStyle` comes in. It accepts the same tagged template literal syntax as `styled` but injects styles directly into the `<head>` with no scoping. Mount it once at the root alongside your `ThemeProvider`.

The trap: `createGlobalStyle` does support props and theme interpolation via `${({ theme }) => theme.fonts.base}`, which tempts you to encode component-level concerns there. Don't. Anything that varies per component belongs in a `styled` definition — global styles should only carry invariants: CSS resets, `:root` custom properties, and base typography on `body` and heading elements. If you find yourself writing `.card` or `.btn` selectors inside `createGlobalStyle`, stop — you're fighting the component model. Also note: `createGlobalStyle` blocks are not deduplicated across multiple mounts in SSR, so keep exactly one instance and colocate it with your theme setup.$escape$,
  $escape$import { createGlobalStyle, ThemeProvider } from 'styled-components';

const GlobalStyle = createGlobalStyle`
  *, *::before, *::after { box-sizing: border-box; }

  body {
    margin: 0;
    font-family: ${({ theme }) => theme.fonts.base};
    background: ${({ theme }) => theme.colors.background};
    color: ${({ theme }) => theme.colors.text};
  }
`;

export function AppRoot({ children }) {
  return (
    <ThemeProvider theme={theme}>
      <GlobalStyle />
      {children}
    </ThemeProvider>
  );
}$escape$,
  $escape$javascript$escape$,
