INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '236b10ba-26f0-47d2-89b3-cd718a32d60a',
  '00000000-0000-0000-0000-000000000001',
  $escape$styled_components — How Automatic Class Scoping Kills Style Bleed$escape$,
  $escape$Every styled-component generates a unique, hashed className at runtime — something like `sc-bdVTJa iBMRpP`. This means two `<Button>` components in completely different feature folders can share the same semantic name without ever colliding. There's no need for BEM, CSS Modules, or manually namespaced selectors.

The encapsulation boundary is the component itself. Styles defined inside `styled.div` are attached only to that component's generated class. Child elements don't inherit your styles unless you explicitly target them with nested selectors (`& > span`) or the `css` helper.

Where bleed still happens: global resets injected via `createGlobalStyle`, third-party stylesheets, or when you reach for `.attrs()` to set a `className` prop directly and accidentally reuse a class name that exists in a global sheet. Also watch for the `shouldForwardProp` gap — forwarding a styled prop to a native DOM element can cause unexpected cascade if the attribute triggers a browser default style.

Use `ThemeProvider` to scope design tokens rather than CSS variables on `:root`, keeping token bleed inside React's component tree.$escape$,
  $escape$import styled, { createGlobalStyle, css } from 'styled-components';

// Scoped — hashed class, zero bleed
export const Card = styled.div`
  padding: 1rem;
  background: ${({ theme }) => theme.surface};

  & > span {
    font-size: 0.875rem; /* only direct <span> children */
  }
`;

// Danger zone — truly global, escapes component scope
export const DangerGlobal = createGlobalStyle`
  a { color: red; } /* affects every <a> in the document */
`;

// Safe token scoping inside the React tree
export const ScopedTheme: React.FC<{ children: React.ReactNode }> = ({ children }) => (
  <ThemeProvider theme={{ surface: '#1e1e2e' }}>{children}</ThemeProvider>
);$escape$,
  $escape$typescript$escape$,
