INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '673fb0a0-46d4-4a37-ae5f-93e5ba371ce6',
  '00000000-0000-0000-0000-000000000001',
  $escape$styled_components Accessibility — focus-visible, Contrast Tokens, and Color-Safe Patterns$escape$,
  $escape$styled_components' template literals give you a clean surface to encode accessibility directly into design tokens and component logic — not as an afterthought.

**focus-visible over focus:** Strip :focus outlines and replace them with :focus-visible using a reusable css helper. Keyboard users get a clear ring; mouse users skip the flash. Pulling the ring color from ThemeProvider keeps it centrally auditable and theme-swappable in one place.

**Contrast via ThemeProvider:** Define colors.primary and colors.onPrimary as a verified pair — WCAG AA requires 4.5:1 for body text, 3:1 for large text. Encode that ratio in your theme object once; every Button and Link that interpolates the pair inherits the correct contrast without per-component overrides.

**Color is never enough:** Red-green error states are invisible to ~8% of male users. Use transient props ($error) to drive both a color change and a ::before pseudo-element that injects a symbol. Chain .attrs() to attach aria-invalid declaratively, keeping semantic meaning co-located with the styles that trigger it — no JSX attribute scatter.$escape$,
  $escape$import styled, { css } from 'styled-components';

const focusRing = css`
  &:focus { outline: none; }
  &:focus-visible {
    outline: 3px solid ${({ theme }) => theme.colors.focusRing};
    outline-offset: 2px;
  }
`;

const Button = styled.button`
  ${focusRing}
  background: ${({ theme }) => theme.colors.primary};
  color: ${({ theme }) => theme.colors.onPrimary}; /* 4.5:1 enforced in theme */
`;

// Pair color with a symbol — never color alone
const StatusBadge = styled.span.attrs<{ $error?: boolean }>(({ $error }) => ({
  'aria-invalid': $error ? 'true' : undefined,
}))<{ $error?: boolean }>`
  color: ${({ $error, theme }) => $error ? theme.colors.error : theme.colors.success};
  &::before { content: ${({ $error }) => $error ? '"✕ "' : '"✓ "'} }
`;$escape$,
  $escape$typescript$escape$,
