INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '0d5ea324-a795-4054-8a26-574deb600297',
  '00000000-0000-0000-0000-000000000001',
  $escape$styled-components Bundle Optimization — Dead Styles, Font Subsetting, and Icon Strategy$escape$,
  $escape$styled-components injects styles at runtime, so classic PurgeCSS has nothing to scan — your 'dead CSS' problem is actually dead component files shipping inside your JS bundle. Fix this with babel-plugin-styled-components and the { pure: true } option: it wraps every styled.* and styled() call with /*#__PURE__*/, letting Webpack and Rollup tree-shake components that are imported but never rendered.

For fonts, avoid top-level @import in a separate CSS file. Declare @font-face inside createGlobalStyle with unicode-range so browsers only fetch the glyph subsets your UI actually uses. Pair it with font-display: swap to protect LCP.

For icons, never wrap an entire icon library with styled() — each unused icon's SVG markup and style sheet entry still ships. Instead, use SVGR to import individual SVG files as React components and wrap each one with a single styled() call. One file, one import, one class name. Keep static props like size and color in attrs() rather than dynamic interpolations to reduce the number of unique class names styled-components generates at runtime.$escape$,
  $escape$import { createGlobalStyle, styled } from 'styled-components';
import { ReactComponent as ArrowSVG } from './icons/arrow.svg';

// Font subsetting — only Latin glyphs fetched
export const GlobalStyles = createGlobalStyle`
  @font-face {
    font-family: 'Inter';
    src: url('/fonts/inter-latin.woff2') format('woff2');
    unicode-range: U+0000-00FF;
    font-display: swap;
  }
`;

// Icon: static attrs() keeps class count low
export const ArrowIcon = styled(ArrowSVG).attrs<{ $size?: number }>(({ $size = 16 }) => ({
  width: $size,
  height: $size,
}))`
  fill: currentColor;
  flex-shrink: 0;
`;$escape$,
  $escape$typescript$escape$,
