INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'd7135523-7ee6-4145-a2e0-ee259f0c73c8',
  '00000000-0000-0000-0000-000000000001',
  $escape$styled-components Testing — Why Snapshots Lie and Chromatic Doesn't$escape$,
  $escape$Snapshot testing with styled-components has a critical blind spot: dynamic state. Even with `jest-styled-components` — which inlines resolved CSS rules into snapshots rather than capturing opaque `sc-bdVxga` hashes — you only test the static render. A `Button` using `${({ $variant }) => variants[$variant]}` gets snapshotted for one prop value; hover pseudo-states, `:focus-visible` outlines, and CSS transitions are invisible to Jest.

Chromatic (Storybook-native) and Percy fix this by rendering your `ThemeProvider`-wrapped stories in a real browser and pixel-diffing against a baseline. Write one story per styled variant and Chromatic catches when `${props => props.theme.colors.primary}` silently changes after a theme token update. For `createGlobalStyle` resets and `keyframes` animations, visual regression is the only reliable signal — no DOM node exists to snapshot. Use Chromatic's `ignoreSelectors` to suppress known dynamic animations and keep the diff signal clean.$escape$,
  $escape$import 'jest-styled-components';
import { render } from '@testing-library/react';
import { ThemeProvider } from 'styled-components';
import { Button } from './Button';
import { theme } from './theme';

test('primary button snapshot', () => {
  const { container } = render(
    <ThemeProvider theme={theme}>
      <Button $variant="primary" />
    </ThemeProvider>
  );
  // Captures resolved CSS — but misses :hover, :focus-visible,
  // transitions, and media queries. Use Chromatic stories for those.
  expect(container.firstChild).toMatchSnapshot();
});$escape$,
  $escape$typescript$escape$,
