INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '7ee57071-d7a2-49b6-a08b-777fb620261c',
  '00000000-0000-0000-0000-000000000001',
  $escape$styled_components — When to Extract a Component vs. Reach for the css Helper$escape$,
  $escape$The `css` helper lets you share style blocks across multiple components — but it's not a free pass to avoid extraction. When you find yourself interpolating the same `css` block in 3+ `styled.*` calls, that's a signal to extract a proper component instead. The `css` helper has a hidden cost: it generates styles at the call site each time, so React's reconciler can't cache it across renders without wrapping in a stable reference defined outside the component tree.

Arbitrary prop interpolations (`${({ isActive }) => isActive && css`...`}`) are powerful but dangerous at scale. Each unique prop combination injects a new CSS class into the stylesheet. Prefer discrete prop variants using `.attrs()` or `shouldForwardProp` to keep the injected class count predictable and avoid stylesheet bloat.

When your styled component's template literal exceeds ~15 lines, extract it — past that threshold you lose the inline readability benefit with none of the performance gains of a plain component. Use `ThemeProvider` tokens (`${({ theme }) => theme.colors.primary}`) over hardcoded values everywhere; this is styled-components' equivalent of a centralized design token config and makes global rebrands a one-file change.$escape$,
  $escape$import styled, { css } from 'styled-components';

// Define css blocks OUTSIDE the component — stable reference, no re-injection
const focusRing = css`
  outline: 2px solid ${({ theme }) => theme.colors.focus};
  outline-offset: 2px;
`;

const Button = styled.button<{ $variant: 'primary' | 'ghost' }>`
  ${focusRing}
  background: ${({ theme, $variant }) =>
    $variant === 'primary' ? theme.colors.primary : 'transparent'};
  padding: ${({ theme }) => theme.spacing.md};
`;

// ❌ Avoid: inline factory injects a new class on every render
// const Bad = styled.div`${() => css`color: red;`}`;
$escape$,
